import { Component, OnInit, OnDestroy, inject } from '@angular/core';
import { CommonModule } from '@angular/common';
import { ReactiveFormsModule, FormBuilder, FormGroup, Validators } from '@angular/forms';
import { Router, ActivatedRoute } from '@angular/router';
import { TaskService } from '../../services/task.service';
import { Task, TaskPriority, TaskStatus } from '../../models/task.model';
import { NavbarComponent } from '../navbar/navbar.component';
import { CanComponentDeactivate } from '../../guards/unsaved-changes.guard';
import { Subject, Observable } from 'rxjs';
import { takeUntil } from 'rxjs/operators';

@Component({
  selector: 'app-task-edit',
  standalone: true,
  imports: [CommonModule, ReactiveFormsModule, NavbarComponent],
  templateUrl: './task-edit.component.html',
  styleUrls: ['./task-edit.component.scss']
})
export class TaskEditComponent implements OnInit, OnDestroy, CanComponentDeactivate {
  private fb = inject(FormBuilder);
  private taskService = inject(TaskService);
  private router = inject(Router);
  private route = inject(ActivatedRoute);
  private destroy$ = new Subject<void>();

  taskForm!: FormGroup;
  submitted = false;
  loading = false;
  initialLoading = true;
  error = '';
  success = false;
  taskId = '';

  // Enums for dropdowns
  TaskPriority = TaskPriority;
  TaskStatus = TaskStatus;
  priorityOptions = Object.values(TaskPriority);
  statusOptions = Object.values(TaskStatus);

  ngOnInit(): void {
    this.initializeForm();
    this.loadTask();
  }

  ngOnDestroy(): void {
    this.destroy$.next();
    this.destroy$.complete();
  }

  initializeForm(): void {
    this.taskForm = this.fb.group({
      title: ['', [Validators.required, Validators.minLength(3), Validators.maxLength(200)]],
      description: ['', [Validators.required, Validators.minLength(10), Validators.maxLength(2000)]],
      priority: [TaskPriority.MEDIUM, Validators.required],
      status: [TaskStatus.PENDING, Validators.required],
      dueDate: [''],
      category: [''],
      tags: [''],
      starred: [false]
    });
  }

  loadTask(): void {
    this.taskId = this.route.snapshot.paramMap.get('id') || '';

    if (!this.taskId) {
      this.error = 'Task ID not found';
      this.initialLoading = false;
      return;
    }

    this.taskService.getTaskById(this.taskId)
      .pipe(takeUntil(this.destroy$))
      .subscribe({
        next: (task) => {
          this.populateForm(task);
          this.initialLoading = false;
        },
        error: (error) => {
          this.error = error.message || 'Failed to load task';
          this.initialLoading = false;
        }
      });
  }

  populateForm(task: Task): void {
    const tagsString = task.tags ? task.tags.join(', ') : '';
    const dueDateValue = task.dueDate ? task.dueDate.split('T')[0] : '';

    this.taskForm.patchValue({
      title: task.title,
      description: task.description,
      priority: task.priority,
      status: task.status,
      dueDate: dueDateValue,
      category: task.category || '',
      tags: tagsString,
      starred: task.starred || false
    });
  }

  get f() {
    return this.taskForm.controls;
  }

  onSubmit(): void {
    this.submitted = true;
    this.error = '';

    if (this.taskForm.invalid) {
      return;
    }

    this.loading = true;
    const formValue = this.taskForm.value;

    const taskData = {
      title: formValue.title,
      description: formValue.description,
      priority: formValue.priority,
      status: formValue.status,
      dueDate: formValue.dueDate ? new Date(formValue.dueDate).toISOString() : undefined,
      category: formValue.category || undefined,
      tags: formValue.tags ? formValue.tags.split(',').map((t: string) => t.trim()).filter((t: string) => t) : [],
      starred: formValue.starred || false
    };

    this.taskService.updateTask(this.taskId, taskData)
      .pipe(takeUntil(this.destroy$))
      .subscribe({
        next: () => {
          this.success = true;
          this.loading = false;
          setTimeout(() => {
            this.router.navigate(['/tasks']);
          }, 1500);
        },
        error: (error) => {
          this.error = error.message || 'Failed to update task';
          this.loading = false;
        }
      });
  }

  cancel(): void {
    this.router.navigate(['/tasks']);
  }

  /**
   * Guard method to prevent navigation with unsaved changes
   */
  canDeactivate(): Observable<boolean> | boolean {
    // If form has no changes and not loading, allow navigation
    if (!this.taskForm.dirty && !this.loading) {
      return true;
    }

    // If form has been submitted successfully, allow navigation
    if (this.success) {
      return true;
    }

    // If form is loading, prevent navigation
    if (this.loading) {
      return false;
    }

    // Form has unsaved changes, ask for confirmation
    if (this.taskForm.dirty) {
      return confirm('You have unsaved changes. Do you want to leave without saving?');
    }

    return true;
  }
}
<app-navbar></app-navbar>

<div class="task-form-container">
  <div class="form-header">
    <h1>Update Task</h1>
  </div>

  <!-- Initial Loading State -->
  @if (initialLoading) {
    <div class="loading-container">
      <div class="spinner"></div>
      <p>Loading task...</p>
    </div>
  }

  @if (!initialLoading) {
    <!-- Error Message -->
    @if (error) {
      <div class="alert alert-error">
        <span class="alert-icon">⚠️</span>
        <span>{{ error }}</span>
      </div>
    }

    <form [formGroup]="taskForm" (ngSubmit)="onSubmit()" class="task-form">
      <!-- Title Field -->
      <div class="form-group">
        <label for="title" class="form-label">Task Title <span class="required">*</span></label>
        <input
          type="text"
          id="title"
          formControlName="title"
          class="form-control"
          [class.is-invalid]="submitted && f['title'].errors"
          placeholder="Enter task title"
          [disabled]="loading"
        />
        @if (submitted && f['title'].errors) {
          <div class="field-error">
            @if (f['title'].errors['required']) {
              <span>Title is required</span>
            }
            @if (f['title'].errors['minlength']) {
              <span>Title must be at least 3 characters</span>
            }
            @if (f['title'].errors['maxlength']) {
              <span>Title cannot exceed 200 characters</span>
            }
          </div>
        }
      </div>

      <!-- Description Field -->
      <div class="form-group">
        <label for="description" class="form-label">Description <span class="required">*</span></label>
        <textarea
          id="description"
          formControlName="description"
          class="form-control textarea"
          [class.is-invalid]="submitted && f['description'].errors"
          placeholder="Enter task description"
          rows="5"
          [disabled]="loading"
        ></textarea>
        @if (submitted && f['description'].errors) {
          <div class="field-error">
            @if (f['description'].errors['required']) {
              <span>Description is required</span>
            }
            @if (f['description'].errors['minlength']) {
              <span>Description must be at least 10 characters</span>
            }
            @if (f['description'].errors['maxlength']) {
              <span>Description cannot exceed 2000 characters</span>
            }
          </div>
        }
      </div>

      <!-- Priority and Status Row -->
      <div class="form-row">
        <!-- Priority Field -->
        <div class="form-group">
          <label for="priority" class="form-label">Priority <span class="required">*</span></label>
          <select
            id="priority"
            formControlName="priority"
            class="form-control"
            [disabled]="loading"
          >
            @for (priority of priorityOptions; track priority) {
              <option [value]="priority">{{ priority }}</option>
            }
          </select>
        </div>

        <!-- Status Field -->
        <div class="form-group">
          <label for="status" class="form-label">Status <span class="required">*</span></label>
          <select
            id="status"
            formControlName="status"
            class="form-control"
            [disabled]="loading"
          >
            @for (status of statusOptions; track status) {
              <option [value]="status">{{ status }}</option>
            }
          </select>
        </div>
      </div>

      <!-- Due Date Field -->
      <div class="form-group">
        <label for="dueDate" class="form-label">Due Date</label>
        <input
          type="date"
          id="dueDate"
          formControlName="dueDate"
          class="form-control"
          [disabled]="loading"
        />
      </div>

      <!-- Category Field -->
      <div class="form-group">
        <label for="category" class="form-label">Category</label>
        <input
          type="text"
          id="category"
          formControlName="category"
          class="form-control"
          placeholder="e.g., Work, Personal, Shopping"
          [disabled]="loading"
        />
      </div>

      <!-- Tags Field -->
      <div class="form-group">
        <label for="tags" class="form-label">Tags <span class="hint">(comma-separated)</span></label>
        <input
          type="text"
          id="tags"
          formControlName="tags"
          class="form-control"
          placeholder="e.g., urgent, important, follow-up"
          [disabled]="loading"
        />
      </div>

      <!-- Form Actions -->
      <div class="form-actions">
        <button
          type="submit"
          class="btn btn-primary"
          [disabled]="loading"
        >
          @if (!loading) {
            <span>Update Task</span>
          } @else {
            <span class="spinner">
              <span class="spinner-dot"></span> Updating...
            </span>
          }
        </button>
        <button
          type="button"
          class="btn btn-secondary"
          (click)="cancel()"
          [disabled]="loading"
        >
          Cancel
        </button>
      </div>
    </form>
  }
</div>
